INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('land-agent-moex-00196', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「我的故鄉不止一個，我住過的地方都是故鄉。」（周作人〈故鄉的野菜〉） 文中所表現對「故鄉」的態度，與下列何者相距最遠？', '["月亮永是故鄉明", "日久他鄉成故鄉", "此心安處即吾鄉", "心泰身寧是歸處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00197', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '張玉芸：「位於英格蘭中部的寇茨渥區，有許多綿延的山路環繞。這跟台灣的高山 峻嶺很不同，這些曲折交錯的彎曲山路，總是充滿一種很溫柔的美麗。此地除了自 然美景很吸引人之外，在一戶農莊外面的店面也很特別，那是一個無人看顧的菜攤 子。上面放置一些青菜和水果，也標示著價錢以及有一個收納金錢的盒子。多年來 行經此地多次，攤子主人從未出現過。他讓顧客自行購買付費，他全然相信他的客 戶。」（張玉芸〈信任其實是一種循環〉） 根據本文，作者認為無人看顧的攤子得以持續經營最重要的原因是：', '["環境的自然美好", "博愛的思想表現", "信任的人際關係", "價格的公道合理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00198', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '重重疊疊的山巒，環抱著一個小小的村莊；彎彎曲曲的小河，從我家門前流過；披 著滿身新綠的垂柳，像少女美麗的秀髮，輕拂著水面上的微波。 故鄉，有如一個溫柔恬靜的少女； 故鄉，好似一個勇敢慷慨的兒郎； 故鄉，有清朗的明月，閃爍的繁星； 有四時不謝的鮮花，有清脆婉轉的鳥聲。 她似一幅畫，又像一首詩；她是我心上的永久戀人，我時時刻刻不能忘！（謝冰瑩 〈故鄉〉） 依據上文，作者對於故鄉的描寫著重在：', '["故鄉裡少女、兒郎的戀愛故事", "故鄉的地理位置以及特殊風貌", "故鄉所流傳的曲河與垂柳傳奇", "故鄉是個遙遠清晰的美好記憶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00199', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '張愛玲：「擁擠是中國戲劇與中國生活裏的要素之一。中國人是在一大群人之間呱 呱墮地的，也在一大群人之間死去──有如十七八世紀的法國君王。中國人在哪裏 也躲不了旁觀者。上層階級的女人，若是舊式的，住雖住在深閨裏，早上一起身便 沒有關房門的權利。冬天，棉製的門簾擋住了風，但是門還是大開的，歡迎著闔家 大小的調查。清天白日關著門，那是非常不名譽的事。即使在夜晚，門閂上了，只 消將窗紙一舐，屋裏的情形也就一目了然。婚姻與死亡更是公眾的事了。鬧房的甚 至有藏在床底下的。病人『迴光返照』的時候，黑壓壓聚了一屋子人聽取臨終的遺 言。」（張愛玲《流言》） 根據本文，可推知作者所強調的中國人特性是：', '["世事洞明，人情練達", "重視群體，不重隱私", "懷想先人，慎終追遠", "夜不閉戶，路不拾遺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00200', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '老子曰：「人之生也柔弱，其死也堅強。萬物草木之生也柔脆，其死也枯槁。故堅 強者死之徒，柔弱者生之徒。是以兵強則不勝，木強則兵。強大處下，柔弱處上。」 （老子《道德經》） 下列那一個選項最接近老子的觀點？', '["柔能克剛", "物盡其用", "欲翕固張", "剛柔並濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00201', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '文學作品中，經常藉「物」表達情感，下列選項何者與「思念故鄉」的情感無關？', '["胡馬依北風，越鳥巢南枝", "狐狸馳赴穴，飛鳥翔故林", "兔從狗竇入，雉從梁上飛", "草蟲鳴何悲，孤雁獨南翔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00202', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「極目兮長望，白雲四茫茫。鴟鴉飽腲腇，鸞鳳饑徬徨。駿馬放石磧，蹇驢能至堂。 天高不可問，鷦鷯在滄浪。」（寒山子《寒山詩集》） 本詩的主旨是：', '["牛驥同一皂，雞棲鳳凰食", "駿馬蹇驢皆控勒，鞭教戰勝出沙場", "賢愚千載知誰是，滿眼蓬蒿共一丘", "驊騮拳跼不能食，蹇驢得志鳴春風"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00203', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '下列各應用文詞語，說明完全正確的是：', '["「璧謝」是致送禮物表示謝意", "訃聞中死者四十歲以上可用「享壽」", "對女老師之夫可稱「師父」或「師公」", "對他人稱自己的姊姊為「家姊」，稱自己的妹妹為「舍妹」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00204', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '文學創作者，每每語出驚人，以滿足讀者的好奇心理，此乃「誇飾」成立之因素。 下列何者沒有使用這種手法？', '["白髮三千丈，緣愁似箇長", "君不見黃河之水天上來，奔流到海不復回", "在看不見的枝椏間，有一隻淘氣的鳥兒在叫著", "我和那一個？朱小姐？早八百年就吹了"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00205', 'land-agent', 'land-agent-moex-105-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '以下成語的用字，何者正確無誤？①形容做事果決，可用「破斧沉舟」  ②比喻同', '["祝福早生貴子，可用「熊羆入夢」", "頭髮掉落稀 少，可用「童山濯濯」  ⑤動作快捷迅速，可用「風馳電轍」", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "c93f2befde9f", "answer_pdf_sha1": "6aa8da7d1cdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL)
